return $input.all().map(item => {
  const keyboards = item.json.keyboards ?? [];

  const cutoff_days = keyboards[0]
    .map(btn => btn.text.match(/\[(.+?)\]/))
    .find(Boolean);

  const start_date = keyboards[1]
    .map(btn => btn.text.match(/\[(.+?)\]/))
    .find(Boolean);

  return {
    json: {
      ...item.json,
      current_cutoff_days: cutoff_days ? cutoff_days[1] : null,
      current_start_date: start_date ? start_date[1] : null,
    },
  };
});

